Register-ArgumentCompleter -Native -CommandName file -ScriptBlock {
  param ([string]$wordToComplete, [System.Management.Automation.Language.CommandAst]$commandAst, [int]$cursorPosition)
  @(if ($wordToComplete.StartsWith('-')) {
      '--help', '-v', '--version', '-m', '--magic-file=', '-z', '--uncompress', '-Z', '--uncompress-noreport', '-b', '--brief', '-c', '--checking-printout', '-e', '--exclude=apptype', '--exclude=ascii', '--exclude=cdf', '--exclude=compress', '--exclude=csv', '--exclude=elf', '--exclude=encoding', '--exclude=soft', '--exclude=tar', '--exclude=json', '--exclude=simh', '--exclude=text', '--exclude=tokens', '--exclude-quiet=apptype', '--exclude-quiet=ascii', '--exclude-quiet=cdf', '--exclude-quiet=compress', '--exclude-quiet=csv', '--exclude-quiet=elf', '--exclude-quiet=encoding', '--exclude-quiet=soft', '--exclude-quiet=tar', '--exclude-quiet=json', '--exclude-quiet=simh', '--exclude-quiet=text', '--exclude-quiet=tokens', '-f', '--files-from=', '-F', '--separator=', '-i', '--mime', '--apple', '--extension', '--mime-type', '--mime-encoding', '-k', '--keep-going', '-l', '--list', '-L', '--dereference', '-h', '--no-dereference', '-n', '--no-buffer', '-N', '--no-pad', '-0', '--print0', '-p', '--preserve-date', '-P', '--parameter', '-r', '--raw', '-s', '--special-files', '-S', '--no-sandbox', '-C', '--compile', '-d', '--debug'
    }).Where{ $_ -like "$wordToComplete*" }
}
